test_pipeline.pipe.diff_text:
--- test_pipeline.pipe
+++ test_pipeline.pipe
@@ -0,0 +1,34 @@
+task echo_hello {

+    params: {

+        x: int

+    }

+    run: {

+        echo "hello\n"

+        echo "${params.x}" >> ${workspace}/results.txt

+    }

+    output: "task_${params.x}"

+}

+

+task readResults_ {

+    params: {}

+    run: {

+        cat results.txt

+    }

+    success: {

+        results_file: equals("results.txt", "1\n2\n")

+        stdout: contains(stdout, "1\n2\n")

+    }

+}

+

+task main {

+    params: {}

+    run: {

+        echo "Finished."

+    }

+    requires: {

+        fail(readResults_());

+        echo_hello(1);

+        echo_hello(x=2);

+        readResults_()

+    }

+}
